// Flatten all issues from epics + noEpic into a single list
const data = $input.first().json;
const allIssues = [];

for (const epic of (data.epics || [])) {
  for (const issue of epic.issues) {
    allIssues.push({
      key: issue.key,
      summary: issue.summary,
      status: issue.status,
      priority: issue.priority,
      assignee: issue.assigneeName || 'Unassigned',
      updated: issue.updated,
      created: issue.created,
      dueDate: issue.dueDate,
      labels: issue.labels || [],
      epicKey: issue.epicKey,
      lastComment: issue.lastComment,
      commentCount: issue.commentCount,
      daysSinceUpdate: issue.daysSinceUpdate
    });
  }
}

for (const issue of (data.noEpic || [])) {
  allIssues.push({
    key: issue.key,
    summary: issue.summary,
    status: issue.status,
    priority: issue.priority,
    assignee: issue.assigneeName || 'Unassigned',
    updated: issue.updated,
    created: issue.created,
    dueDate: issue.dueDate,
    labels: issue.labels || [],
    epicKey: null,
    lastComment: issue.lastComment,
    commentCount: issue.commentCount,
    daysSinceUpdate: issue.daysSinceUpdate
  });
}

return allIssues.map(i => ({ json: i }));

// Collect all issues for board summary
const data = $('Fetch Jira Issues').first().json;
const allIssues = [];

for (const epic of (data.epics || [])) {
  for (const issue of epic.issues) {
    allIssues.push({
      key: issue.key,
      summary: issue.summary,
      status: issue.status,
      priority: issue.priority,
      assignee: issue.assigneeName || 'Unassigned',
      updated: issue.updated,
      dueDate: issue.dueDate,
      labels: issue.labels || []
    });
  }
}
for (const issue of (data.noEpic || [])) {
  allIssues.push({
    key: issue.key,
    summary: issue.summary,
    status: issue.status,
    priority: issue.priority,
    assignee: issue.assigneeName || 'Unassigned',
    updated: issue.updated,
    dueDate: issue.dueDate,
    labels: issue.labels || []
  });
}

return [{ json: { tickets: allIssues, jql: 'project = TEAM ORDER BY updated DESC' } }];
